{
  "domain_analysis": {
    "business_context": "A logistics platform introducing automated route optimization for drivers at shift start, with dynamic recalculation triggers, customer notification windows, vehicle class constraints, and configurable stop duration. This spans multiple bounded contexts: route planning, fleet/driver management, delivery lifecycle, and customer notifications.",
    "bounded_context": "This feature crosses at least four bounded contexts: (1) Route Planning — owns route calculation, optimization, recalculation triggers, and stop time estimates; (2) Fleet Management — owns driver profiles, vehicle class licensing, zone assignments, and shift lifecycle; (3) Delivery Management — owns delivery lifecycle (pending, in-transit, failed, completed), zone assignment of parcels, and parcel attributes (size, weight, vehicle class requirement); (4) Customer Notification — owns notification triggers, delivery proximity windows, and customer communication preferences. Each context must respect its own invariants and communicate via domain events, not direct coupling.",
    "ubiquitous_language": [
      { "term": "Shift", "definition": "A bounded work period for a driver, beginning when they clock in and ending when they clock out or complete all assigned stops. A shift is the lifecycle anchor for route assignment." },
      { "term": "Optimized Route", "definition": "An ordered sequence of delivery stops calculated to minimize total travel time or distance for a driver within their assigned zone during their active shift." },
      { "term": "Zone", "definition": "A geographic partition of the service area. Deliveries belong to a zone; drivers are assigned to zones. Zone boundaries are an operational concern owned by Fleet Management." },
      { "term": "Pending Delivery", "definition": "A delivery that has been accepted into the system but not yet assigned to a driver's route or not yet attempted. Only pending deliveries are eligible for route assignment." },
      { "term": "Failed Delivery", "definition": "A delivery attempt that did not result in successful handoff to the recipient. Triggers route recalculation because the stop is removed or deprioritized from the active route." },
      { "term": "Route Recalculation", "definition": "The act of recomputing the optimized route in response to a material change: new delivery added, delivery failure, or driver deviation. Produces a new ordered stop sequence." },
      { "term": "Driver Deviation", "definition": "When a driver's actual GPS position or stop sequence diverges from the suggested route beyond a defined threshold. This is a recalculation trigger." },
      { "term": "Next 3 Stops Window", "definition": "A proximity threshold defined as the upcoming three stops in the driver's current route. When a delivery enters this window, the customer receives a notification." },
      { "term": "Vehicle Class", "definition": "A classification of vehicle type (e.g., motorcycle, van, truck, freight). Each driver is licensed for one or more vehicle classes. Each delivery requires a minimum vehicle class based on parcel attributes." },
      { "term": "Licensed Vehicle Class", "definition": "The set of vehicle classes a driver is certified and legally permitted to operate. This is a hard constraint — not a preference." },
      { "term": "Stop Duration Estimate", "definition": "The estimated time a driver spends at each delivery stop. Defaults to 4 minutes system-wide but is overridable per zone by the operations team." },
      { "term": "Operations Override", "definition": "A zone-level configuration set by the operations team that overrides system defaults (e.g., stop duration). These are soft business policies, not invariants." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A driver MUST NOT be assigned a delivery whose required vehicle class exceeds or is incompatible with the driver's licensed vehicle class.",
      "invariant": true,
      "invariant_justification": "This is a legal and physical constraint. A motorcycle physically cannot carry freight, and a driver operating outside their license class violates transportation regulations. Violation means unsafe deliveries and legal liability.",
      "testable_assertion": "For every delivery D on driver X's route: D.requiredVehicleClass ∈ X.licensedVehicleClasses."
    },
    {
      "id": "BR-2",
      "rule": "A driver MUST NOT be assigned deliveries outside their assigned zone.",
      "invariant": true,
      "invariant_justification": "Zone assignment is an operational boundary that ensures coverage models, insurance, and labor agreements are respected. Cross-zone assignment breaks dispatch accountability and SLA tracking.",
      "testable_assertion": "For every delivery D on driver X's route: D.zone == X.assignedZone."
    },
    {
      "id": "BR-3",
      "rule": "Route assignment occurs automatically when a driver starts their shift, using all pending deliveries in their zone as input.",
      "invariant": false,
      "invariant_justification": "This is a workflow policy. The business could choose manual assignment or batch assignment instead. The trigger (shift start) is a business decision, not a physical or data integrity constraint.",
      "testable_assertion": "When driver X starts a shift and there are N pending deliveries in their zone, a route is generated containing only those N deliveries (filtered by vehicle class compatibility)."
    },
    {
      "id": "BR-4",
      "rule": "The route MUST be recalculated when a new pending delivery is added to the driver's zone during an active shift.",
      "invariant": false,
      "invariant_justification": "This is a responsiveness policy. The business could choose to batch recalculations or defer new deliveries to the next shift. It is a policy choice, not a data integrity constraint.",
      "testable_assertion": "Given driver X has an active route in zone Z, when a new delivery is created in zone Z, then X's route is recalculated to include the new delivery."
    },
    {
      "id": "BR-5",
      "rule": "The route MUST be recalculated when a delivery on the active route is marked as failed.",
      "invariant": false,
      "invariant_justification": "Policy decision about how to handle failures. The system could alternatively just skip the stop without full recalculation.",
      "testable_assertion": "Given driver X has delivery D on their route, when D is marked as failed, then X's route is recalculated excluding D (or reprioritizing D per retry policy)."
    },
    {
      "id": "BR-6",
      "rule": "The route MUST be recalculated when the driver manually deviates from the suggested route.",
      "invariant": false,
      "invariant_justification": "This is a UX/operational policy. Some systems allow deviation without recalculation. The threshold for 'deviation' is itself configurable.",
      "testable_assertion": "Given driver X deviates from the suggested route beyond the configured threshold, then a new optimized route is calculated from X's current position to remaining stops."
    },
    {
      "id": "BR-7",
      "rule": "Customers MUST be notified when their delivery enters the 'next 3 stops' window on the driver's active route.",
      "invariant": false,
      "invariant_justification": "The notification window size (3 stops) is a business policy. A VP could change it to 2 or 5. The notification itself is a customer experience decision, not a system integrity constraint.",
      "testable_assertion": "When a route is calculated or recalculated, for each delivery that is now within the first 3 upcoming stops and was not previously notified, a customer notification is dispatched."
    },
    {
      "id": "BR-8",
      "rule": "The default estimated time per delivery stop is 4 minutes, overridable per zone by the operations team.",
      "invariant": false,
      "invariant_justification": "Both the default (4 minutes) and the override mechanism are operational policies. These are tuning parameters, not integrity constraints.",
      "testable_assertion": "Route time estimation uses the zone-specific override if configured, otherwise falls back to 4 minutes per stop."
    },
    {
      "id": "BR-9",
      "rule": "A route MUST only contain deliveries with status 'pending'. Completed, cancelled, or in-progress deliveries must not appear as unvisited stops.",
      "invariant": true,
      "invariant_justification": "Assigning a non-pending delivery to a route produces corrupt state — the driver would be directed to deliver something already delivered or cancelled. This is data integrity.",
      "testable_assertion": "For every unvisited stop on any active route, the corresponding delivery status == 'pending' or 'assigned'."
    },
    {
      "id": "BR-10",
      "rule": "A driver can have at most one active route at a time.",
      "invariant": true,
      "invariant_justification": "Multiple simultaneous active routes for a single driver is a data consistency violation — the driver can only physically be on one route. This would cause double-assignment of deliveries.",
      "testable_assertion": "For any driver X at any point in time, COUNT(active routes for X) <= 1."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A driver starts their shift and there are 12 pending deliveries in their zone, 2 of which require freight vehicle class, and the driver is licensed for van only",
      "when": "The system generates the initial route",
      "then": "The route contains exactly 10 deliveries (the 2 freight deliveries are excluded), ordered by optimization algorithm, and the driver sees their first stop"
    },
    {
      "id": "AC-2",
      "given": "A driver has an active route with 8 remaining stops",
      "when": "A new pending delivery is added to their zone that is compatible with their vehicle class",
      "then": "The route is recalculated to include the new delivery in its optimized position, and total ETA is updated using the zone's stop duration estimate"
    },
    {
      "id": "AC-3",
      "given": "A driver has an active route and delivery #4 of 8 is marked as failed",
      "when": "The failure is recorded",
      "then": "The route is recalculated with the failed delivery removed from the active sequence, remaining stops are re-optimized from the driver's current position"
    },
    {
      "id": "AC-4",
      "given": "A driver has an active route and physically drives to a location not matching the next suggested stop",
      "when": "The deviation exceeds the configured threshold",
      "then": "The route is recalculated from the driver's actual current position to all remaining unvisited stops"
    },
    {
      "id": "AC-5",
      "given": "A driver has an active route with 7 remaining stops and stop #3 belongs to customer C",
      "when": "The route is calculated or recalculated and customer C's delivery is now at position 1, 2, or 3",
      "then": "Customer C receives a notification that their delivery is within the next 3 stops, and this notification is sent at most once per route generation (no duplicate notifications on subsequent recalculations if already notified)"
    },
    {
      "id": "AC-6",
      "given": "Zone 'Downtown' has a stop duration override of 6 minutes and Zone 'Suburban' uses the default",
      "when": "Routes are calculated for drivers in each zone",
      "then": "Downtown route ETA uses 6 min/stop and Suburban route ETA uses 4 min/stop"
    },
    {
      "id": "AC-7",
      "given": "A driver starts their shift and there are zero pending deliveries in their zone",
      "when": "The system attempts route generation",
      "then": "No route is created, the driver is placed in an idle/awaiting state, and the system will generate a route when the first compatible delivery arrives in the zone"
    },
    {
      "id": "AC-8",
      "given": "Two drivers are active in the same zone",
      "when": "Route generation occurs",
      "then": "Each pending delivery is assigned to exactly one driver's route (no double-assignment), and the assignment considers both drivers' vehicle class constraints"
    },
    {
      "id": "AC-9",
      "given": "A driver has an active route and a new delivery is added to their zone that requires a vehicle class the driver is not licensed for",
      "when": "Route recalculation is triggered",
      "then": "The incompatible delivery is NOT added to this driver's route, regardless of optimization benefit"
    }
  ],

  "edge_cases": [
    {
      "scenario": "Multiple recalculation triggers fire simultaneously (new delivery added AND driver deviates at the same moment)",
      "expected_behavior": "Recalculations must be serialized or deduplicated per driver. The system should coalesce concurrent triggers into a single recalculation using the latest state, not produce two competing routes."
    },
    {
      "scenario": "All deliveries in a zone require freight class but only motorcycle drivers are on shift",
      "expected_behavior": "No routes are generated. Deliveries remain pending. An alert should be raised to operations that there are unassignable deliveries due to vehicle class mismatch."
    },
    {
      "scenario": "Driver deviates, triggering recalculation, but the recalculated route is identical to the original minus the deviation",
      "expected_behavior": "The system should still issue the recalculated route (confirming it). Customer notifications already sent should NOT be re-sent."
    },
    {
      "scenario": "A delivery is added and immediately cancelled before route recalculation completes",
      "expected_behavior": "The recalculated route must use current delivery state at completion time — the cancelled delivery must not appear on the route. Eventual consistency: route reflects latest truth."
    },
    {
      "scenario": "A driver's shift ends while they still have remaining stops on their route",
      "expected_behavior": "Spec does not define this. Remaining deliveries should revert to pending and become available for reassignment. The route should be marked as incomplete, not failed."
    },
    {
      "scenario": "Customer notification is triggered but the customer has no valid contact method on file",
      "expected_behavior": "The notification attempt is logged as undeliverable. The delivery itself continues — notification failure must never block delivery operations."
    },
    {
      "scenario": "Operations team sets stop duration override to 0 minutes or a negative value",
      "expected_behavior": "The system must validate the override: minimum stop duration should have a floor (e.g., >= 1 minute). Reject invalid configurations with a clear error."
    },
    {
      "scenario": "A zone boundary is redrawn while drivers have active routes in that zone",
      "expected_behavior": "Active routes should complete under their original zone assignment. New deliveries follow new boundaries. Rezoning mid-route risks orphaning stops."
    },
    {
      "scenario": "Rapid succession of failed deliveries — driver marks 5 of 8 stops as failed within 2 minutes",
      "expected_behavior": "Each failure triggers recalculation, but the system should debounce/coalesce to avoid 5 sequential recalculations. The final route contains only the 3 remaining valid stops."
    },
    {
      "scenario": "Two drivers in the same zone start their shift at the exact same moment",
      "expected_behavior": "Route generation must handle concurrent assignment atomically. Pending deliveries are partitioned between drivers — no delivery is assigned to both routes."
    }
  ],

  "business_impact": {
    "financial": "Route optimization directly reduces fuel costs, increases deliveries-per-shift (driver utilization), and reduces overtime. Dynamic recalculation captures new revenue (mid-shift deliveries served same-day). Vehicle class enforcement avoids regulatory fines and insurance claim denials. Estimated 10-25% efficiency gain over manual routing.",
    "operational": "Eliminates manual dispatch for route planning. Increases dispatcher capacity to handle exceptions rather than routine assignments. Introduces new operational dependency on real-time GPS accuracy and route optimization engine availability. Operations team gains zone-level tuning via stop duration overrides. Risk: optimization engine downtime blocks all route assignment — needs fallback strategy.",
    "user": "Drivers get clear, optimized guidance — reduces decision fatigue. Customers get proactive proximity notifications — reduces 'where is my package' inquiries. However, frequent route recalculations could frustrate drivers if the route keeps changing. The 'next 3 stops' notification sets a concrete customer expectation that must be met to avoid trust erosion.",
    "risk": "Technical: route optimization engine is a single point of failure for shift start. If it's down, no driver gets a route. Domain: the spec does not address multi-driver zones (delivery partitioning), shift-end handling, or retry policy for failed deliveries — these are gaps that will surface in production. Compliance: vehicle class enforcement is a legal requirement, not optional — must be treated as a hard gate, never a soft filter.",
    "stakeholders_affected": [
      { "group": "Drivers", "impact": "Primary users. Gain automated routing but lose autonomy. Frequent recalculations could be disruptive. Must trust the optimization to adopt it." },
      { "group": "Customers", "impact": "Receive proactive delivery proximity notifications. Sets expectation of accuracy — if the 'next 3 stops' estimate is wrong, trust erodes." },
      { "group": "Operations Team", "impact": "Gains zone-level tuning knobs (stop duration). Loses direct route control. Needs alerting for edge cases (vehicle class mismatches, unassignable deliveries)." },
      { "group": "Dispatchers", "impact": "Workload shifts from manual route building to exception handling. Role evolves significantly." },
      { "group": "Finance/Management", "impact": "Expects measurable efficiency gains. Needs KPIs: deliveries/shift, fuel cost/delivery, on-time rate." },
      { "group": "Compliance/Legal", "impact": "Vehicle class enforcement is a regulatory requirement. Must be auditable. Any bypass is a liability event." }
    ]
  },

  "confidence": {
    "level": 55,
    "reasoning": "The spec clearly defines single-driver happy path but leaves critical multi-driver, shift-end, failure-retry, and concurrency scenarios undefined. Vehicle class constraint is clear. Notification rule is clear but lacks idempotency guidance. The biggest gap is multi-driver zone partitioning — this is a core routing problem that the spec ignores entirely. Stop duration override lacks validation rules. Deviation threshold is referenced but never defined.",
    "high_confidence_areas": [
      "Vehicle class constraint is a hard invariant — clearly defined and legally grounded",
      "Recalculation triggers are well-enumerated (3 explicit triggers)",
      "Customer notification window (next 3 stops) is concrete and testable",
      "Stop duration default and override mechanism is clear"
    ],
    "low_confidence_areas": [
      "Multi-driver zone behavior — how are pending deliveries partitioned between drivers in the same zone?",
      "Shift-end behavior — what happens to remaining stops when a shift ends?",
      "Failed delivery retry policy — does a failed delivery re-enter the pending pool? When?",
      "Deviation threshold definition — what constitutes a 'deviation' (distance? wrong stop order? GPS drift?)",
      "Recalculation concurrency — no guidance on debouncing or coalescing rapid triggers",
      "Notification idempotency — should customers be re-notified if a recalculation keeps them in the 3-stop window?"
    ],
    "assumptions": [
      "Each driver is assigned to exactly one zone per shift",
      "A delivery's required vehicle class is determined by parcel attributes (size, weight, type) and is set at delivery creation time",
      "Route optimization considers travel time/distance — the specific algorithm is an implementation detail, not a domain rule",
      "The 'next 3 stops' window is recalculated on every route change, not based on the original route",
      "Failed deliveries are removed from the active route but their lifecycle (retry, return to pending) is handled by a separate process"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "Multi-driver zone partitioning is unspecified. When two drivers are active in the same zone, how are pending deliveries divided? Options include: geographic sub-partitioning, load balancing by count, optimization across both routes simultaneously, or first-come-first-served. This is a core routing concern that fundamentally changes the optimization problem.",
      "affected_stakeholders": ["Drivers", "Operations Team", "Customers"],
      "options": [
        "A: Optimize across all drivers in the zone simultaneously (global optimization — complex but optimal)",
        "B: Partition deliveries geographically within the zone, then optimize per driver (simpler, suboptimal)",
        "C: Assign all pending to first driver, overflow to second (simple, unfair, inefficient)"
      ],
      "recommendation": "Option A (global optimization) is the correct domain answer for a logistics platform, but Option B is a pragmatic starting point. Need product team to confirm."
    },
    {
      "type": "ambiguity",
      "description": "Deviation threshold is undefined. The spec says 'driver manually deviates from the suggested route' but does not define what constitutes a deviation. Is it: visiting stops out of order? Being more than X meters from the expected path? Missing a turn? Each interpretation produces different recalculation frequency and driver experience.",
      "affected_stakeholders": ["Drivers", "Operations Team"],
      "options": [
        "A: Deviation = driver completes a stop out of the suggested order",
        "B: Deviation = driver GPS position is >500m from the expected route path for >2 minutes",
        "C: Both A and B are deviations"
      ],
      "recommendation": "Option A is the most meaningful deviation from a business perspective — stop order changes affect the optimization. GPS path deviation (Option B) may be caused by traffic and is less actionable."
    },
    {
      "type": "missing_context",
      "description": "Shift-end behavior is completely undefined. What happens to undelivered stops when a driver's shift ends? This has direct customer impact (delivery delays), driver impact (overtime expectations), and operational impact (reassignment workflow).",
      "affected_stakeholders": ["Drivers", "Customers", "Operations Team", "Finance/Management"],
      "options": [
        "A: Remaining deliveries revert to pending and are available for next shift/driver",
        "B: Driver is expected to complete all assigned deliveries regardless of shift end",
        "C: Operations is alerted and manually decides per delivery"
      ],
      "recommendation": "Option A with an alert to operations. Forcing drivers to exceed shifts (Option B) creates labor law issues."
    },
    {
      "type": "missing_context",
      "description": "Failed delivery retry policy is not addressed. When a delivery is marked as failed and removed from the route, does it re-enter the pending pool for the same driver? A different driver? After a delay? This lifecycle gap will cause operational confusion.",
      "affected_stakeholders": ["Customers", "Operations Team", "Drivers"],
      "options": [
        "A: Failed delivery returns to pending pool immediately, eligible for reassignment to any driver",
        "B: Failed delivery enters a 'retry queue' with a configurable delay before becoming pending again",
        "C: Failed delivery requires manual operations review before retry"
      ],
      "recommendation": "Option B — immediate retry (Option A) likely fails again for the same reason. Manual review (Option C) doesn't scale. A configurable delay respects the failure reason."
    },
    {
      "type": "ambiguity",
      "description": "Route optimization fallback is undefined. If the optimization engine is unavailable when a driver starts their shift, the driver cannot begin work. There is no specified degraded mode (e.g., FIFO ordering, manual dispatch, last-known-good route).",
      "affected_stakeholders": ["Drivers", "Customers", "Operations Team"],
      "options": [
        "A: Fall back to FIFO (first-in-first-out) ordering by delivery creation time",
        "B: Fall back to geographic nearest-neighbor (simple but suboptimal)",
        "C: Block shift start until optimization engine recovers"
      ],
      "recommendation": "Option B (nearest-neighbor fallback) provides a reasonable route without full optimization. Option C is unacceptable — it blocks all operations."
    }
  ],

  "rejection_reasons": []
}

